			preferencias.extensaoAtiva = false;
			browser.storage.local.set({'extensaoAtiva':false});
			browser.runtime.sendMessage({tipo: 'iconeNavegador', valor: '+PJe: Desligado', icone: 'ico_16_off.png'});
