							ic_sisbajud2.id = "extensaoPje_bt_sisbajud2_gigs_3_ic_sisbajud2_" + pos;
							bt_sisbajud2.title = "Consultar Teimosinha";
							ic_sisbajud2.className = "fas fa-search";
