									let check = setInterval(async function() {
										if (verificador) {
											clearInterval(check);
											browser.storage.onChanged.removeListener(logStorageChange);								
										}
									}, 1000);

									function logStorageChange(changes, area) {
										let changedItems = Object.keys(changes);
										for (let item of changedItems) {
											if (item == "tempAR") {
												verificador = true;
											}
										}
									}

