	let btSyncronizarPJeCalc = await esperarElemento('#maisPje_bt_gigs_sync', null, 100);
	if (!btSyncronizarPJeCalc) {
		console.log('btSyncronizarPJeCalc')
		let ancora3 =  await esperarElemento('div[id="checklist-exec"] div[class*="pad-container"]'); ;//o primeiro que aparece é o total da execução
		if (ancora3) {
			await sleep(preferencias.maisPje_velocidade_interacao);
			let urlDaUltimaRequisicao = await obterUrlDoNetworkRequest('.jus.br/pje-gigs-api/api/execucao/processo/');
			let idProcesso = await obterIdProcessoDaUrl(urlDaUltimaRequisicao);
			
			if (!idProcesso) { 
				idProcesso = await obterIdProcessoDaUrl();
			}
			// document.location.href.substring(document.location.href.search("/processo/")+10, document.location.href.search("/detalhe"));
			let result = await pjeApiObterValorExecucaoPJeCalc(idProcesso);

			ancora3.style.display = 'grid'; //alinha os botões
			ancora3.style.setProperty('grid-template-columns','45% 10% 45%');

			let divSuporte = document.createElement("div");
			divSuporte.style = "margin-top: 45%;color: #6e6e6e;";
			divSuporte.title = "Sincronizar com o PJeCalc";
			divSuporte.setAttribute("aria-label","Sincronizar com o PJeCalc");

			let botao3 = document.createElement("i");			
			botao3.id = "maisPje_bt_gigs_sync";
			botao3.className = "fa fa-sync";
			botao3.style.cursor = "pointer";			
			
			let label = document.createElement("span");
			label.style = "font-size: 11px; color: orangered; font-style: italic; margin-top: -15px; opacity: 0.5;white-space: nowrap;";
			label.innerText = 'PJeCalc: R$ ' + result.valor + " em " + result.data;			
			
			botao3.onclick = async function () {								
				// alert(JSON.stringify(result));
				let campo1 = document.querySelector('div[id="checklist-exec"] div[class*="pad-container"] input');
				destacar(campo1);
				await preencherInput(campo1,result.valor);
				campo1.dispatchEvent(simularTecla('keydown',46)); //DEL				

				let aviso = await esperarElemento('simple-snack-bar','Valor alterado com sucesso!')
				aviso.querySelector('button').click(); //fecha o aviso
				
				let campo2 = document.querySelector('div[id="checklist-exec"] div[class*="pad-container"] input[type="date"]');
				destacar(campo2);
				let dt = new Date(result.ano,result.mes,result.dia);
				await preencherInput(campo2,dt,null,'data');									

				aviso = await esperarElemento('simple-snack-bar','Valor alterado com sucesso!')
				await sleep(800);
				aviso.querySelector('button').click(); //fecha o aviso

				gigsCriarMenu();//clicar crachá
			};

			divSuporte.appendChild(botao3);
			ancora3.firstElementChild.insertAdjacentElement('afterend', divSuporte);
			ancora3.appendChild(label);

		}
	
	}

