	function buscaARGigs(numAR, parte) {
		console.log("Extensão maisPJE (" + agora() + "):    |_ " + numAR + " : " + parte);		
		if (numAR != null) {
			let var1 = browser.storage.local.set({'tempAR': parte});
			Promise.all([var1]).then(values => {
				let parametros = 'dependent=yes,';					
				parametros += 'left=' + ((preferencias.gigsGigsWidth)/2) + ',';
				parametros += 'top=0,';
				parametros += 'width=' + (window.screen.width/2) + ',';
				parametros += 'height=' + window.screen.height;

				let url = 'https://rastreamento.correios.com.br/app/index.php?Registros='+numAR;				
				if (Array.isArray(preferencias.modulo9.ecarta)) {
					if (preferencias.modulo9.ecarta[0] == true && (preferencias.modulo9.ecarta[1] != '' || preferencias.modulo9.ecarta[1] != 'undefined')) {
						url = preferencias.modulo9.ecarta[1] + numAR;
					}
				}
				window.open(url, '_blank', parametros);
			});
		} else {
			console.log("Extensão maisPJE (" + agora() + "): Registro(AR) não encontrado!");
			browser.runtime.sendMessage({tipo: 'criarAlerta', valor: 'Registro(AR) não encontrado!', icone: '1'});
		}
	}

