async function analiseDoTipoDeRecurso() {
	return new Promise(async resolve => {
		let idProcesso = await obterIdProcessoDaUrl();
		let tipoDeRecurso = await obterTipoDeRecurso(idProcesso);
		console.log(tipoDeRecurso)
		if (tipoDeRecurso) {
			//apenas escolhe automaticamente os tipos de recurso mais comuns
			// let tipoRecursoOrdinario = ['Recurso Ordinário','Recurso Ordinário - Rito Sumaríssimo','Recurso Ordinário Trabalhista']; //posição 0 é o tipo de recurso.. os demais são as opções decorrente dele
			// let tipoRecursoAgravoInstrumento = ['Agravo de Instrumento','Agravo de Instrumento em Agravo de Petição','Agravo de Instrumento em Recurso Ordinário']
			let opcaoEscolhida = '';			
			if (tipoDeRecurso == 'Agravo de Instrumento') {
				let faseDoProcesso = await obterFaseIdProcessoViaApi(idProcesso);
				console.log(faseDoProcesso);
				switch (faseDoProcesso) {
					case 'Conhecimento':
						opcaoEscolhida = 'Agravo de Instrumento em Recurso Ordinário';
						break
					case 'Excecução':
						opcaoEscolhida = 'Agravo de Instrumento em Agravo de Petição';
						break
					default:
						opcaoEscolhida = '';
						break
				}
			} else if (tipoDeRecurso == 'Recurso Ordinário') {
				let d = await esperarElemento('pje-cabecalho pje-descricao-processo')
				let ritoProcesso = await obterRitoProcessoDoTexto(d.innerText);
				console.log(ritoProcesso);
				switch (ritoProcesso) {
					case 'ATOrd':
						opcaoEscolhida = 'Recurso Ordinário Trabalhista';
						break
					case 'ATSum':
						opcaoEscolhida = 'Recurso Ordinário - Rito Sumaríssimo';
						break
					default:
						opcaoEscolhida = '';
						break
				}
			} else if (tipoDeRecurso == 'Agravo de Petição') {
				opcaoEscolhida = tipoDeRecurso + '[exato]';
			}

			if (opcaoEscolhida) {
				await escolherOpcaoTeste2('pje-remeter-processo form mat-select[placeholder="Classe judicial"]',opcaoEscolhida);
			}

			return resolve(true);	
		}
		
	});

	async function obterTipoDeRecurso(idProcesso) {
		return new Promise(async resolve => {
			//desativei para buscar tb movimentos = true.. já que na api o parametro movimentos eh false
			// const dados = await apis.timelineProcesso.executar(preferencias.trt, {'idProcesso': idProcesso, 'buscarMovimentos' : 'true'});
			let resultado = '';
			let url = 'https://' + preferencias.trt + '/pje-comum-api/api/processos/id/' + idProcesso + '/timeline?somenteDocumentosAssinados=false&buscarMovimentos=true&buscarDocumentos=true';
			let resposta = await fetch(url);
			let dados = await resposta.json();
			
			if (dados) {
				let tiposQueInterrompem = ['Conclusos os autos para julgamento Proferir sentença']; //o movimento de proferir sentença interrompe
				let tiposQueImportam = ['Recurso Ordinário','Agravo de Petição','Agravo de Instrumento','Recurso de Revista'];
				for (const [pos, item] of dados.entries()) {
					if ((!item.documento) && tiposQueInterrompem.includes(item.titulo)) { break } //somente movimentos interrompe
					if (tiposQueImportam.includes(item.tipo)) { resultado = item.tipo; break }
				}
				return resolve(resultado);
			} else {
				return resolve('ERRO2');
			}
			
		});
	}
}

//FUNÇÃO RESPONSÁVEL POR ADICIONAR O BOTÃO PRAZO EM LOTE NOS DESPACHOS/DECISÃO/SENTENÇA
async function addBotaoPrazoEmLote() {
	//INSERE O BOTÃO PARA INSERIR PRAZO EM LOTE
	return new Promise(async resolve => {
		let tempo_espera = preferencias.maisPje_velocidade_interacao + 1000;
		let ancora = await esperarElemento('pje-intimacao-automatica',null,tempo_espera);
		if (!ancora) { return resolve(false) }
		let jaExiste = await esperarElemento('button[id="pjextension_prazoEmLote"]',null,tempo_espera);
		if (jaExiste) { return resolve(true) }
		
		var el = document.querySelector('div[class="controle-intimacao"]')
		if (!el) { return resolve(true) }
		var botao = document.createElement("button");
		botao.textContent = "Prazo em lote";
		botao.id = "pjextension_prazoEmLote";
		botao.style = "cursor: pointer; margin-left: 10px;"
		botao.onmouseenter = function () {
			if (!document.getElementById('maisPje_barra_bt_pzoLote')) {

				let barra_bt_pzoLote_temp = document.createElement("div");
				barra_bt_pzoLote_temp.id = "maisPje_barra_bt_pzoLote";
				barra_bt_pzoLote_temp.style = "z-index: 100; height: auto; position: absolute; background-color: rgb(255, 255, 255); text-align: center; border-radius: 3px; display: grid; grid-template-columns: 1fr 1fr 1fr; align-items: center;margin-top: 5px;margin-left: -3px; gap: 10px;";
				barra_bt_pzoLote_temp.onmouseleave = function (e) {
					barra_bt_pzoLote_temp.className = "maisPje-fade-out";
					setTimeout(function(){				
						document.getElementById('maisPje_barra_bt_pzoLote').remove();
					}, 250);
				};

				let listaDePrazos = preferencias.extrasPrazoEmLote;

				for (const [pos, prazo] of listaDePrazos.entries()) {
					let elBotao = criarElemento('button', "cursor: pointer; position: relative; top: 20%;  z-index: 1; background-color: rgb(0, 120, 170); border: 1px solid rgb(102, 174, 204); outline: rgb(0, 111, 157) solid 1px; border-radius: 3px; color: white;min-width: 64px;line-height: 30px;padding: 0 10px;", prazo + ' dias');
					elBotao.setAttribute('prazo',prazo);
					elBotao.onclick = function () {
						this.parentElement.remove();
						executar(this.getAttribute('prazo'));
					};
					barra_bt_pzoLote_temp.appendChild(elBotao);
				}

				let btOutro = criarElemento('button', "cursor: pointer; position: relative; top: 20%;  z-index: 1; background-color: rgb(0, 120, 170); border: 1px solid rgb(102, 174, 204); outline: rgb(0, 111, 157) solid 1px; border-radius: 3px; color: white;min-width: 64px;line-height: 30px;padding: 0 10px;", 'outro');
				btOutro.onclick = async function () {
					this.parentElement.remove();
					let pzOutro = await criarCaixaDePergunta('text', 'Digite o prazo em dias Úteis:\n');
					executar(pzOutro);
				};
				barra_bt_pzoLote_temp.appendChild(btOutro);

				botao.appendChild(barra_bt_pzoLote_temp);
			}
		};			
		el.appendChild(botao);

		mapearDestinatario();

		return resolve(true);
	});
	
	async function executar(prazoEmLote) {
		let el = document.querySelectorAll('mat-form-field[class*="prazo"]');
		if (!el) {
			return
		}
		fundo(true);
		
		let map = [].map.call(
			el, 
			function(elemento) {				
				let el2 = elemento.querySelector('input');
				el2.focus();
				el2.value = prazoEmLote;
				triggerEvent(el2, 'input');
			}
		);
		
		await clicarBotao('button', 'Gravar', true);
		fundo(false);
	}

	async function mapearDestinatario() {
		let tabela = document.querySelectorAll('pje-intimacao-automatica tbody tr span[class="destinario"]');
		if (!tabela) {
			return
		}
		fundo(true);
		
		let idProcesso = await obterIdProcessoDaUrl();
		let partes = await obterPartesDoProcesso(idProcesso, false);
		console.log(partes)
		let poloAtivo = partes.poloAtivo.map(({ nome }) => nome);
		console.log(poloAtivo);
		let poloPassivo = partes.poloPassivo.map(({ nome }) => nome);
		console.log(poloPassivo);		
		let poloOutros = partes.poloOutros.map(({ nome }) => nome);
		console.log(poloOutros);
		let poloOutrosTipo = partes.poloOutros.map(({ tipo }) => tipo);
		console.log(poloOutrosTipo);

		let map = [].map.call(
			tabela, 
			function(linha) {
				let icone = document.createElement('i');
				icone.className = 'mat-tooltip-trigger fa fa-user icone-padrao';
				icone.style = 'padding-right: 10px;';

				if (poloAtivo.includes(linha.innerText)) { //polo ativo
					console.log('polo ativo')
					icone.style.color = '#0b9a38';
					linha.parentElement.parentElement.setAttribute('maisPje_destinatario','Polo Ativo');
				} else if (poloPassivo.includes(linha.innerText)) { //polo passivo
					console.log('polo passivo')
					icone.style.color = '#fb6e09';
					linha.parentElement.parentElement.setAttribute('maisPje_destinatario','Polo Passivo');
				} else if (poloOutros.includes(linha.innerText)) { //polo ativo
					console.log('polo outros')
					let tipo = poloOutrosTipo[poloOutros.indexOf(linha.innerText)];
					console.log('   |___tipo: ' + tipo)
					linha.parentElement.parentElement.setAttribute('maisPje_destinatario','Polo Outros - ' + tipo);
					if (tipo == 'PERITO') {
						icone.style.color = '#a127fd';
					} else if (tipo == 'CUSTOS LEGIS') {
						icone.style.display = 'none';
					} else {
						icone.style.color = '#585858';
					}
				}
				linha.insertAdjacentElement('afterbegin',icone);
			}
		);

		//marca a atividade como finalizada
		document.querySelector('pje-intimacao-automatica tbody')?.setAttribute('maisPje_partesIdentificadas','true');
		
		fundo(false);
	}
}

//FUNÇÃO RESPONSÁVEL POR ADICIONAR O BOTÃO DE MARCAR/DESMARCAR TODOS OS CHECKBOXES
async function addBotaoMarcarDesmarcarTodos() {
	//INSERE O BOTÃO PARA INSERIR CHECK MARCAR/DESMARCAR TODOS
	return new Promise(async resolve => {
		let tempo_espera = preferencias.maisPje_velocidade_interacao + 1000;
		let ancora = await esperarElemento('pje-intimacao-automatica',null,tempo_espera);
		if (!ancora) { return resolve(false) }
		
		let el = ancora.querySelector('div[class="cabecalho"]')?.nextSibling;
		if (!el) { return resolve(false) }
		
		if (!document.getElementById('maisPje_desmarcar')) {
			let ckbox1 = document.createElement("button");
			ckbox1.setAttribute('type', 'button');
			ckbox1.id = "maisPje_desmarcar";
			ckbox1.innerText = "Desmarcar Todos";
			ckbox1.style = 'cursor: pointer; padding: 10px; background-color: rgb(250, 250, 250); filter: brightness(1); font-size: 14px; color: gray; border: 0; border-radius: 25px;';
			ckbox1.onmouseenter  = function () { this.style.filter = 'brightness(0.95)' }
			ckbox1.onmouseleave  = function () { this.style.filter = 'brightness(1)' }
			ckbox1.onclick = function () { fundo(true);executar('1', ancora, ckbox1.checked); };
			el.appendChild(ckbox1);
		}
		
		if (!document.getElementById('maisPje_marcar')) {
			let ckbox2 = document.createElement("button");
			ckbox2.setAttribute('type', 'button');
			ckbox2.id = "maisPje_marcar";
			ckbox2.innerText = "Marcar Todos";
			ckbox2.style = 'cursor: pointer; padding: 10px; background-color: rgb(250, 250, 250); filter: brightness(1); font-size: 14px; color: gray; border: 0; border-radius: 25px; margin: 0px 14px 0px 14px;';
			ckbox2.onmouseenter  = function () { this.style.filter = 'brightness(0.95)' }
			ckbox2.onmouseleave  = function () { this.style.filter = 'brightness(1)' }
			ckbox2.onclick = function () { fundo(true); executar('2', ancora, ckbox2.checked); };
			el.appendChild(ckbox2);
		}
		
		if (!document.getElementById('maisPje_inverter')) {
			let ckbox3 = document.createElement("button");
			ckbox3.setAttribute('type', 'button');
			ckbox3.id = "maisPje_inverter";
			ckbox3.innerText = "Inverter Selecionados";
			ckbox3.style = 'cursor: pointer; padding: 10px; background-color: rgb(250, 250, 250); filter: brightness(1); font-size: 14px; color: gray; border: 0; border-radius: 25px;';
			ckbox3.onmouseenter  = function () { this.style.filter = 'brightness(0.95)' }
			ckbox3.onmouseleave  = function () { this.style.filter = 'brightness(1)' }
			ckbox3.onclick = function () { fundo(true); executar('3', ancora, ckbox3.checked); };
			el.appendChild(ckbox3);
		}
		return resolve(true);
	});	
	
	function executar(opcao, ancora, valor) {
		// console.log(valor);
		if (!ancora) { return }
		let el = ancora.querySelectorAll('table input[aria-label="Intimar parte"]');
		if (!el) { return }
		
		let map = [].map.call(
			el, 
			function(elemento) {
				// console.log(elemento.checked);
				if (opcao === '1') { // Desmarcar Todos
					if (elemento.checked) {
						elemento.click();
					}
				}
				
				if (opcao === '2') { // Marcar Todos
					if (!elemento.checked) {
						elemento.click();
					}
				}
				
				if (opcao === '3') { // Inverter selecionados
					elemento.click();
				}
			}
		);
		fundo(false);
	}
}

//FUNÇÃO RESPONSÁVEL POR ADICIONAR O BOTÃO TIPO EM LOTE NOS ANEXOS DA CERTIDÃO
function addBotaoTipoEmLote() {
	//INSERE O BOTÃO PARA INSERIR TIPO EM LOTE
	if (!preferencias.extrasSugerirTipoAoAnexar && !preferencias.extrasSugerirDescricaoAoAnexar) {
		return;
	}
	
	if (!document.querySelector('pje-anexar-pdfs')) {
		return;
	} else {

		var listenerclick = async function(e) {
			console.log(e.target + ' : ' + e.target.tagName + ' : ' + e.target.className)
			let alvo = e.target;
			if (!(alvo.tagName == 'DIV' && alvo.className.includes('mat-slide-toggle-'))) {
				e.stopPropagation();	
				if (this.className.includes('maisPJe_anexo_selecionado')) {
					this.classList.remove('maisPJe_anexo_selecionado');
					this.style.outline = 'revert';
				} else {
					this.classList.add('maisPJe_anexo_selecionado');
					this.style.outline = '3px dashed orangered';
				}				
			}
		}

		if (!document.getElementById('pjextension_tipoEmLote')) {
			var el = document.querySelector('pje-anexar-pdfs')
			var botao = document.createElement("button");
			botao.textContent = "Tipo em lote";
			botao.id = "pjextension_tipoEmLote";
			botao.style = "cursor: pointer; margin-left: 10px;"
			botao.onclick = function () {executar()};
			el.insertBefore(botao, el.firstElementChild);
		}
		if (!document.getElementById('pjextension_apagarEmLote')) {
			var el = document.querySelector('pje-anexar-pdfs')
			var botao = document.createElement("button");
			botao.textContent = "Excluir";
			botao.id = "pjextension_apagarEmLote";
			botao.style = "position: absolute; cursor: pointer; right: 10px;"
			botao.onclick = function () {excluir()};
			el.insertBefore(botao, el.firstElementChild);
		}
		if (!document.getElementById('pjextension_marcarEmLote')) {
			var el = document.querySelector('pje-anexar-pdfs')
			var botao = document.createElement("button");
			botao.textContent = "Marcar Todos";
			botao.id = "pjextension_marcarEmLote";
			botao.setAttribute('maisPJe_marcar','true');
			botao.style = "position: absolute; cursor: pointer; right: 70px;"
			botao.onclick = function () {
				if (this.textContent.includes('Desmarcar')) {
					this.textContent = "Marcar Todos";					
				} else {
					this.textContent = "Desmarcar Todos";
				}

				selecionarTodos();
			};
			el.insertBefore(botao, el.firstElementChild);
		}

	}
	
	
	async function executar() {
		let anexos = document.querySelectorAll('pje-item-lista-anexo-pdf');
		if (!anexos) {
			return
		}		
		fundo(true);		
		for (const [pos, anexo] of anexos.entries()) {			
			let apenasOsNovos = anexo.querySelectorAll('.status-anexo-nao-salvo');
			if (apenasOsNovos.length > 0) { await corrigirAnexos(anexo) }
			anexo.onclick = listenerclick;
		}
		fundo(false);
		
		if (preferencias.extrasSugerirTipoAoAnexar) {
			await clicarBotao('button[aria-label="Salvar"]', null, true);
		}
		
		async function corrigirAnexos(elemento) {
			return new Promise(async resolve => {
				if (elemento.querySelector('input[aria-label="Tipo de Documento"]').value == "") {
					let padraoEncontrado = await procuraPadrao(elemento.querySelector('input[aria-label="Descrição"]').value);
					// console.log(padraoEncontrado.tipo + " : " + padraoEncontrado.descricao);
					
					// let selectTipo = elemento.querySelector('input[aria-label="Tipo de Documento"]');
					// selectTipo.setAttribute('maisPJe_anexoPai',elemento.id)
					// selectTipo.addEventListener('blur', function(event) {
					// 	if (['Planilha de Cálculos','Planilha de Atualização de Cálculos'].includes(this.value)) {
					// 		console.log('teta: ' + elemento.id);
					// 		let campoPai = document.querySelector('#'+elemento.id);
					// 		campoPai.removeListener(listenerclick);
					// 		campoPai.classList.remove('maisPJe_anexo_selecionado');
					// 		campoPai.style.outline = 'revert';							
					// 	}
					// });

					if (preferencias.extrasSugerirDescricaoAoAnexar) {
						if (padraoEncontrado.descricao != '') {
							let inputDescricao = elemento.querySelector('input[aria-label="Descrição"]');
							await preencherInput(inputDescricao,padraoEncontrado.descricao);
							let labelDescricao = elemento.querySelector('label[for="' + inputDescricao.id + '"] span');
							labelDescricao.innerText = labelDescricao.innerText + ' (sugestão pelo +PJe) - anterior:' + padraoEncontrado.anterior;
						}
					}
					
					if (preferencias.extrasSugerirTipoAoAnexar) {
						let inputTipo = elemento.querySelector('input[aria-label="Tipo de Documento"]');					
						await escolherOpcao(inputTipo,padraoEncontrado.tipo,5);
						let labelTipo = elemento.querySelector('label[for="' + inputTipo.id + '"] span');
						labelTipo.innerText = labelTipo.innerText + ' (sugestão pelo +PJe)';
					}
					
					return resolve(true);
				}
				return resolve(false);
			});
		}
		
		async function procuraPadrao(texto) {
			return new Promise(async resolve => {
				// let padraoSISBAJUD = /\d{14}\_\d{8}/gm;
				let padraoSISBAJUD = /\S{8}/gm;
				let padraoCCS = /\d{17}\-\d{12}\-/gm;
				let padraoDossieMedico = /\DOSSIE\_\d{11,}/gm;
				let padraoEmail = /(e.?mail)/gmi;
				let padraoRegistroImoveis = /(registro\sde\sim.veis)|(\sCRI\sde\s)|(\d{1,2}\SRI\sde\s)/gmi;
				let padraoRegistroImoveis2 = /(mat.?\s?(?:\.|,|[0-9])*)/gmi;
				let padraoARISP = /[A-Za-z0-9]{32}/gm;
				let padraoContaSIF = /\d{4}\.\d{3}\.\d{8}\-\d{1}/gm;
				let padraoContaBB = /\d{4}\.\d{12,13}/gm;
				let padraoCNIB = /[A-Z0-9]{96}/gm;//5133D5E92C939700A9CE32A474C31B742AC4CC51E0ECBDDFDD6F0D19E0C87810F8E9FDE722C7FC7515D81927D760478D
				let padraoRENAJUDAntigoCancelamento =/(restricoes.retirar)/gm;//restricoes-retirar.jsf


				//OPÇÕES DE JUNTADA DE ENDEREÇO
				let campoDescricaoTexto = document.querySelector('div[class="metadados"] input[aria-label="Descrição"]').value;
				
				//retira o versionamento do documento colocado pelo windows.. Por exemplo: "DOSSIE_Carta_Concessao(2)" transforma em "DOSSIE_Carta_Concessao"
				texto = texto.replace(/(\(\d{1,}\))$/gm,'');					

				if (campoDescricaoTexto.toLowerCase().includes('endereço')) {
					
					if (texto.toLowerCase().includes('renajud')) {
						return resolve({tipo:'Renajud (consulta)',descricao:'endereço RENAJUD',anterior:texto});
					}
					
					if (padraoSISBAJUD.test(texto) && texto.length == 8) {
						return resolve({tipo:'Documento Diverso',descricao:'endereço SISBAJUD',anterior:texto});
					}
					
					if (texto.includes('carta-ordem-endereco')) {
						return resolve({tipo:'Documento Diverso',descricao:'endereço SERASAJUD',anterior:texto});		
					}
					
					if (texto.toLowerCase().includes('sniper')) {
						return resolve({tipo:'Documento Diverso',descricao:'endereço SNIPER',anterior:texto});		
					}
					
					if (texto.toLowerCase().includes('casan')) {
						return resolve({tipo:'Documento Diverso',descricao:'endereço CASAN',anterior:texto});		
					}
					
					if (texto.toLowerCase().includes('celesc')) {
						return resolve({tipo:'Documento Diverso',descricao:'endereço CELESC',anterior:texto});		
					}

					return resolve({tipo:'Documento Diverso',descricao:texto,anterior:texto});
				//OPÇÕES DE JUNTADA DIVERSO
				} else {
					
					if (texto.toLowerCase().includes('renajud')) {
						return resolve({tipo:'Renajud (consulta)',descricao:texto,anterior:texto});
					}
					
					if (padraoSISBAJUD.test(texto) && texto.length == 8) {
						if (campoDescricaoTexto.toLowerCase().includes('desbloqueio')) {
							return resolve({tipo:'Sisbajud (desbloqueio)',descricao:'desbloqueio SISBAJUD',anterior:texto});
						} else {
							return resolve({tipo:'Sisbajud (bloqueio)',descricao:'bloqueio SISBAJUD',anterior:texto});
						}
					}

					if (padraoCNIB.test(texto)) {
						if (campoDescricaoTexto.toLowerCase().includes('cancelamento')) {
							return resolve({tipo:'Documento Diverso',descricao:'Cancelamento CNIB',anterior:texto});
						} else {
							return resolve({tipo:'Documento Diverso',descricao:'Resposta CNIB',anterior:texto});
						}
					} else if (campoDescricaoTexto.toLowerCase().includes('cancelamento') && campoDescricaoTexto.toLowerCase().includes('cnib')) { //para os casos em que o arquivo baixado vem como "detalhe"
						return resolve({tipo:'Documento Diverso',descricao:'Cancelamento CNIB',anterior:texto});
					}

					if (padraoRENAJUDAntigoCancelamento.test(texto)) {
						return resolve({tipo:'Documento Diverso',descricao:'Resposta RENAJUD Cancelamento',anterior:texto});
					}
					
					if (texto.toLowerCase().includes('carta-ordem-endereco')) {
						return resolve({tipo:'Documento Diverso',descricao:'Ordem SERASAJUD',anterior:texto});		
					}
					
					if (texto.toLowerCase().includes('Sniper')) {
						return resolve({tipo:'Documento Diverso',descricao:'Relatório SNIPER',anterior:texto});		
					}
					
					if (texto.toLowerCase().includes('censec')) {
						return resolve({tipo:'Documento Diverso',descricao:'Relatório CENSEC',anterior:texto});		
					}
					
					if (padraoCCS.test(texto)) {
						return resolve({tipo:'Documento Diverso',descricao:'Relatório CCS',anterior:texto});
					}
					
					if (padraoDossieMedico.test(texto)) {
						return resolve({tipo:'Documento Diverso',descricao:'DOSSIE_médico',anterior:texto});
					}
					
					if (padraoRegistroImoveis.test(texto)) {
						return resolve({tipo:'Certidão do Cartório de Registro de Imóveis',descricao:texto,anterior:texto});
					}
					
					if (padraoRegistroImoveis2.test(texto)) {
						return resolve({tipo:'Certidão do Cartório de Registro de Imóveis',descricao:texto,anterior:texto});
					}
					
					if (padraoEmail.test(texto)) {
						return resolve({tipo:'Correspondência ou Mensagem Eletrônica/E-mail',descricao:texto,anterior:texto});
					}
					
					if (padraoARISP.test(texto)) {
						return resolve({tipo:'Documento Diverso',descricao:'Cópia de Matrícula',anterior:texto});
					}					
					
					if (texto.toLowerCase().includes('extrato') && !texto.toLowerCase().includes('cnis')) {
						return resolve({tipo:'Extrato Bancário',descricao:texto,anterior:texto});
					}
					
					if (padraoContaSIF.test(texto)) {
						return resolve({tipo:'Extrato Bancário',descricao:texto,anterior:texto});
					}
					
					if (padraoContaBB.test(texto)) {
						return resolve({tipo:'Extrato Bancário',descricao:texto,anterior:texto});
					}
					
					if (texto.toLowerCase().includes('Cnpjreva_Comprovante.asp')) {
						return resolve({tipo:'Documento Diverso',descricao:'CNPJ - RFB Situação Cadastral',anterior:texto});
					}
					
					if (texto.toLowerCase().includes('ConsultaPublicaExibir.asp')) {
						return resolve({tipo:'Documento Diverso',descricao:'CPF - RFB Situação Cadastral',anterior:texto});
					}
					
					return resolve({tipo:'Documento Diverso',descricao:texto,anterior:texto});
				}
				
				
			});
		}
		
	}

	async function selecionarTodos() {
		let anexos = document.querySelectorAll('pje-item-lista-anexo-pdf');
		if (!anexos) {
			return
		}		
		fundo(true);		
		for (const [pos, anexo] of anexos.entries()) {
			anexo.click();
		}
		fundo(false);
	}

	async function excluir() {
		let anexos = document.querySelectorAll('pje-item-lista-anexo-pdf[class*="maisPJe_anexo_selecionado"]');
		if (!anexos) {
			console.log('nenhum')
			return
		}
		console.log(anexos.length)
		
		fundo(true);		
		for (const [pos, anexo] of anexos.entries()) {
			await clicarBotao(anexo.querySelector('button[aria-label*="Excluir anexo"]'))
			await clicarBotao(document.querySelector('pje-dialog-confirmar-exclusao-pdfs button[aria-label="Excluir este documento"]'))
			await sleep(1000);
		}
		fundo(false);
		
	}


	
}

//FUNÇÕES RESPONSÁVEIS POR CRIAR A ESTRUTURA DOS BOTÕES QUE REPRESENTAM AS AÇÕES AUTOMATIZADAS
async function criarContainer(idContainer='',btFecharOn=false) {
	return new Promise(
		async resolver => {
			let barra = document.querySelector('maisPjeContainerAA');
			if (barra?.id == idContainer) { return }			
			if (barra) { barra.remove() }				
			let ancora = await esperarElemento('#painel-principal-detalhes-processo'); //mudaram pra section na versão 2.14.4
			barra = document.createElement("maisPjeContainerAA");
			barra.id = idContainer;
			barra.style = "height: auto; background-color: rgb(255, 255, 255); border-bottom: 1px solid lightgray; margin-top: 5px; padding-right: 2vw; box-shadow: none; text-align: center; overflow-y: auto; min-height: 50vh; z-index: 99999999;";
			
			if (btFecharOn) {
				let btFecharContainer = document.createElement('button');
				btFecharContainer.style = "position: absolute;cursor: pointer;right: 0;border: none;border-radius: .3vw;width: 1.5vw;height: 1.5vw;background-color:#fdcbc2;--color1: #fdcbc2;--color2: tomato;color: white;font-size: 1.2em;margin: 0.1vw 0.2vw 0vw 0vw; opacity: .5;";
				btFecharContainer.title = 'Fechar';
				btFecharContainer.onmouseenter = function () { this.style.opacity = '1'; }
				btFecharContainer.onmouseleave = function () { this.style.opacity = '.5'; }
				btFecharContainer.onclick = function () { 
					barra.remove();
					corrigirPosicaoElementos();
				}
				let icone = document.createElement('i');
				icone.className = "fa-times fas";
				btFecharContainer.appendChild(icone);
				
				
				
				//aplica à barra o efeito de ao sair dela iniciar a contagem para encerrar o container
				let check;
				let mouseEmCima = false; 
				barra.onmouseleave = function (event) {				
					event.preventDefault();
					if (mouseEmCima) { return }
					// console.log('entrou')
					let velocidadeDeInteracao = preferencias.maisPje_velocidade_interacao;
					velocidadeDeInteracao = parseFloat(velocidadeDeInteracao/1000);
					btFecharContainer.style.animation = 'trocarCorGeral ' + velocidadeDeInteracao + 's';
					mouseEmCima = true;
					let seg = 1;
					check = setInterval(function() {
						seg--;
						if (mouseEmCima && seg < 1) {
							clearInterval(check);
							mouseEmCima = false;							
							btFecharContainer.click();
						}			
						
					}, preferencias.maisPje_velocidade_interacao);
				};
				barra.onmouseenter = function (event) {				
					event.preventDefault();
					btFecharContainer.style.animation = 'unset';
					mouseEmCima = false;
					clearInterval(check);
				};
				
				barra.appendChild(btFecharContainer);
				
			} else {
				barra.onmouseleave = function () {
					this.remove();
					corrigirPosicaoElementos();
				}
			}
			
			ancora.insertBefore(barra, ancora.childNodes[2]);
			resolver(true);
		}
	);
}

async function montarBotoes(lista, acao) {
	return new Promise(async resolve => {
		let faseProcesso = document.querySelector('pje-cabecalho-processo span[class*="descricao-tarefa"]').innerText;
		let padraoFase = /(Conhecimento)|(Execução)|(Liquidação)|(Arquivado)/gmi;
		if (padraoFase.test(faseProcesso)) { 
			faseProcesso = faseProcesso.match(padraoFase).join();
			faseProcesso = removeAcento(faseProcesso.toLowerCase());
		} else {
			faseProcesso = 'todos';
		}

		for (const [pos, aa] of lista.entries()) {
			
			if (aa.tipo) { //É o tipo agrupador, que serve apenas para cadeias de vínculos
				if (aa.tipo.toLowerCase() == 'nenhum') {
					await criarBotao('maisPjeContainerAA', pos, aa.nm_botao, aa.cor, aa.visibilidade, acao, aa.vinculo, faseProcesso, true);
					continue;
				}
			}
			await criarBotao('maisPjeContainerAA', pos, aa.nm_botao, aa.cor, aa.visibilidade, acao, aa.vinculo, faseProcesso);
		}
		corrigirPosicaoElementos();
		resolve(true);
	});
}

async function criarBotao(container, id, nm_botao, cor, visivel, acao, v=['Nenhum'], faseProcesso='todos', agrupador=false) {
	return new Promise(async resolve => {
		ancora = await esperarElemento(container);
		let bt = document.createElement("button");
		bt.id = id;
		bt.name = nm_botao;
		bt.className = "mat-raised-button mat-primary ng-star-inserted";
		if (visivel == "sim" || visivel == faseProcesso) {
			bt.style = "margin: 3px; z-index: 5;" + (cor != "" ? "background-color: " + cor + ";" : "");
		} else {
			bt.style = "display: none;";
		}

		if (agrupador) {
			bt.style.removeProperty('background-color');
			bt.style.background = 'linear-gradient(135deg, #646464 10px, rgb(140, 140, 140) 11px, #CFD0D0 12px)';
			bt.style.color = '#646464';
			bt.style.setProperty('box-shadow','inset 0 0 0 2px rgb(100,100,100)');		
		}

		bt.onclick = acao;
		bt.onmouseenter = function() { criarMapaDosVinculos(nm_botao,v,nm_botao) }
		bt.onmouseleave = function() { if (document.getElementById('maisPjeContainerMapaVinculos')) { document.getElementById('maisPjeContainerMapaVinculos').remove() }}
		
		
		let span = document.createElement("span");
		span.className = "mat-button-wrapper";
		span.innerText = nm_botao;
		bt.appendChild(span);
		
		//perfumaria
		if (v.length > 1 && v != "Nenhum") {
			let perfumaria = document.createElement("span");
			if (agrupador) {
				perfumaria.style = "font-size: 12px; position: relative; left: 22px; top: -17px;";
				perfumaria.innerText = '🔘'
			} else {
				perfumaria.style = "position: absolute; width: 7px; height: 10px; background-color: white; clip-path: polygon(25% 0%, 70% 0%, 40% 35%, 95% 35%, 20% 100%, 40% 55%, 0% 55%); right: 8px; margin: 0.6em -0.3em;"
			}

			bt.appendChild(perfumaria);
		}
		
		ancora.appendChild(bt);
		resolve(true);
	});
}

async function corrigirPosicaoElementos() {
	let ancora = await esperarElemento('button[aria-label="Filtrar"]');
	if (!ancora) { return }
	let altura = ancora.getBoundingClientRect().bottom + 29;
	//move o botão "Esconder Linha do Tempo" para cima
	if (document.querySelector('button[aria-label="Esconder Linha do Tempo"]')) {
		document.querySelector('button[aria-label="Esconder Linha do Tempo"]').style = "top: " + altura + "px;";
	}
	//move o botão "Esconder o GIGS" para cima
	if (document.querySelector('button[aria-label="Esconder o GIGS"]')) {
		document.querySelector('button[aria-label="Esconder o GIGS"]').style = "top: " + altura + "px;";
	}
	//move o botão "Mostrar o GIGS" para cima
	if (document.querySelector('button[aria-label="Mostrar o GIGS"]')) {
		document.querySelector('button[aria-label="Mostrar o GIGS"]').style = "top: " + altura + "px;";
	}
	
}

