async function monitor_janela_censec() {
	console.log("Extensão maisPJE (" + agora() + "): monitor_janela_censec");
	let targetDocumento = document.body;
	let observerDocumento = new MutationObserver(async function(mutationsDocumento) {
		mutationsDocumento.forEach(async function(mutation) {
		if (!mutation.removedNodes[0] && !mutation.addedNodes[0]) { return }

		if (mutation.addedNodes[0]) {
			if (!mutation.addedNodes[0].tagName) { return }
			// console.log("+++++++++ADDNODES: " + mutation.addedNodes[0].tagName + " : " + mutation.addedNodes[0].className + " : " + mutation.addedNodes[0].innerText);

			if (mutation.addedNodes[0].tagName == 'DIV' && mutation.addedNodes[0].innerText.includes('Exportar resultados')) {
				if (document.getElementById('maisPje_imprimirEmLote')) { return }
				let ancora = mutation.addedNodes[0].querySelector('button');
				inserirBotoes(ancora.parentElement);
			}
		}

		if (mutation.removedNodes[0]) {
			if (!mutation.removedNodes[0].tagName) { return }
			console.log("----------REMOVEDNODES: " + mutation.removedNodes[0].tagName + " : " + mutation.removedNodes[0].className + " : " + mutation.removedNodes[0].innerText);
			if (mutation.removedNodes[0].tagName == 'DIV' && mutation.removedNodes[0].className.includes('cdk-overlay-backdrop')) {
				if (document.querySelector('lacm-loading')) { document.querySelector('lacm-loading').setAttribute('maisPje','true') }
			}			
		}

		});
	});
	let configDocumento = { childList: true, subtree:true }
	observerDocumento.observe(targetDocumento, configDocumento); //inicia o MutationObserver

	function inserirBotoes(ancora) {
		let atalho1 = document.createElement("button");
		atalho1.id = "maisPje_imprimirEmLote";
		atalho1.className = "mat-button mat-button-base";
		atalho1.style = "background-color: #e7e7e7; color: #009bb3; margin-right: 3px; vertical-align: middle;";
		atalho1.innerText = "Imprimir em Lote";
		atalho1.onmouseenter = function () {atalho1.style.backgroundColor = '#d2d2d2'};
		atalho1.onmouseleave = function () {atalho1.style.backgroundColor = '#e7e7e7'};
		atalho1.onclick = function () {imprimirEmLote()};
		ancora.appendChild(atalho1);
	}

	async function imprimirEmLote() {
		let linhas = await esperarColecao('div[class="material-table"] mat-row');
		for (const [pos, linha] of linhas.entries()) {
			console.log('linha ' + pos + ': ' + linha.innerText);
			console.log('*******' + linha.children.length)
			linha.scrollIntoView({behavior: 'smooth',block: 'start'});
			linha.style.backgroundColor = (linha.children.length > 5) ? '#c3d336' : 'unset';
			await clicarBotao(linha.querySelector('spa-link-button button'));
			await escolherOpcaoTeste('mat-select[aria-label="Items per page:"]','100');
			await esperarElemento('lacm-loading[maisPje="true"]');
			await sleep(1000);
			await clicarBotao('button[id="maisPje_assistenteImpressao_bt_copiar"]');
			await sleep(1000);
			await clicarBotao('button','arrow_back_ios');
			await sleep(1000);
		}
	}
}

async function monitor_janela_sniper() {
	console.log("Extensão maisPJE (" + agora() + "): monitor_janela_sniper");
	let targetDocumento = document.body;
	let observerDocumento = new MutationObserver(async function(mutationsDocumento) {
		mutationsDocumento.forEach(async function(mutation) {
		if (!mutation.removedNodes[0] && !mutation.addedNodes[0]) { return }

		if (mutation.addedNodes[0]) {
			if (!mutation.addedNodes[0].tagName) { return }
			// console.log("+++++++++ADDNODES: " + mutation.addedNodes[0].tagName + " : " + mutation.addedNodes[0].className + " : " + mutation.addedNodes[0].innerText);
			if (mutation.addedNodes[0].tagName == 'SPAN' && (mutation.addedNodes[0].innerText.includes('pessoa encontrada para processo') || mutation.addedNodes[0].innerText.includes('pessoas encontradas para processo'))) {
				let ancora = mutation.addedNodes[0].querySelectorAll('strong')[1];
				consultaPJe(ancora);
			}
			
		}

		if (mutation.removedNodes[0]) {
			if (!mutation.removedNodes[0].tagName) { return }
			// console.log("----------REMOVEDNODES: " + mutation.removedNodes[0].tagName + " : " + mutation.removedNodes[0].className + " : " + mutation.removedNodes[0].innerText);
			
			if (mutation.removedNodes[0].tagName == 'DIV' && mutation.removedNodes[0].className.includes('progress-bar progress-bar-loaded')) {
				console.log('SNIPER - PAGINA RECARREGADA');
				if (document.location.href.includes('/investigacao-de-bens/') && document.location.href.includes('/parte/')) {

					if (document.location.href.includes('?maisPje')) { fundo(true) }

					if (document.location.href.includes('?maisPje=processos')) {
						await clicarBotao('div[role="tab"]','Processos');
						let spinnerBusca = await esperarElemento('mat-tab-body mat-spinner',null,500);
						if (spinnerBusca) { console.log('spinner2'); await esperarDesaparecer(spinnerBusca) }
						await clicarBotao('#maisPje_assistenteImpressao_bt_copiar');
						fundo(false);
						await clicarBotao('a[href*="/investigacao-de-bens/"]');//voltar
					}

					if (document.location.href.includes('?maisPje=dados')) {
						await clicarBotao('#maisPje_assistenteImpressao_bt_copiar');
						fundo(false);			
						await clicarBotao('a[href*="/investigacao-de-bens/"]');//voltar
					}

				} else if(document.location.href.includes('/investigacao-de-bens/')) {
					addBotoesImprimirProcessos();
					
					//grafo está ativado
					let grafo = await esperarElemento('tabs-vision[label2="Grafo"] div[aria-selected="true"]','Grafo',500);
					
					if (grafo) { //existe grafo
						//ajusta a posição do botão zoom
						let ancora = await esperarElemento('graph');
						ancora.querySelector('div[class="graph-zoom"]').style = 'right: unset; left: 1vw; bottom: 8vh;';

						var listenerclick = async function(event) {
							if (document.querySelector('#maispje_sniper_grafo_imprimir[maisPJeAtivado]') && event.target.tagName == 'CANVAS') {
								await clicarBotao('graph div[class="extra-buttons"] button[class*="print-btn"]'); //clica na impressão		
							}
						}
						
						// document.body.addEventListener('pointerdown', listenerclick);
						document.body.addEventListener('pointerdown', listenerclick);

						//criar botao imprimir todo os clicados
						if (!document.getElementById("maispje_sniper_grafo_imprimir")) {
							let ancora = document.querySelector('graph div[class="extra-buttons"]');

							let bt = document.createElement("button");
							bt.id = "maispje_sniper_grafo_imprimir";
							bt.title = "Ativar/Desativar";
							bt.style = "cursor: pointer; position: relative; border-radius: 25px; font-weight: 500; pointer-events: all; background-color: white; border: medium; width: 10vw; display: grid; grid-template-columns: 1fr 2fr; align-content: center; margin-right: 15px;";
							bt.onclick = async function () {
								
								if (this.hasAttribute('maisPJeAtivado')) {
									this.removeAttribute('maisPJeAtivado');
									this.firstElementChild.style.textAlign = 'initial';
									this.firstElementChild.style.backgroundColor = 'rgb(0,0,0,0.5)';
									//reexibe o botão nativo de imprimir
									document.querySelectorAll('div[class="extra-buttons"] button')[1].style.visibility = 'revert';									


								} else {
									this.setAttribute('maisPJeAtivado','true');
									this.firstElementChild.style.textAlign = 'end';									
									this.firstElementChild.style.backgroundColor = 'rgb(12, 153, 0)';
									//oculta o botão nativo de imprimir
									document.querySelectorAll('div[class="extra-buttons"] button')[1].style.visibility = 'hidden';
								}

							}

							let span1 = document.createElement("span")
							span1.id = 'maispje_sniper_grafo_imprimir_icone'
							span1.style = "align-content: center;text-align: center;font-size: 1.05em;";
							span1.innerText = "Imprimir ao clicar";				

							let span2 = document.createElement("span")
							span2.id = 'maispje_sniper_grafo_imprimir_ativador';
							span2.style = 'text-align: initial; pointer-events: none; filter: opacity(0.3);background-color: rgb(0,0,0,0.5);border-radius: 25px;margin: 0 5px 0 5px;padding: 0px 2px 2px 2px;';
							span2.innerText = "🔘";							
							
							bt.appendChild(span2); //ativador
							bt.appendChild(span1); //icone
							ancora.insertBefore(bt, ancora.firstChild);
						}
						
					}

				}



			}
		}

		});
	});
	let configDocumento = { childList: true, subtree:true }
	observerDocumento.observe(targetDocumento, configDocumento); //inicia o MutationObserver

	//destaca melhor a aba ativa: Tabelas   Grafo
	let tabTabelas = await esperarElemento('tabs-vision[label2="Grafo"] div[aria-posinset="1"]');
	if (tabTabelas) {
		tabTabelas.style.backgroundColor = 'rgba(0, 92, 187, 0.38)';
		tabTabelas.style.borderRadius = '15px 15px 0 0';
		tabTabelas.addEventListener('click', function() {
			this.style.backgroundColor = 'rgba(0, 92, 187, 0.38)';
			this.style.borderRadius = '15px 15px 0 0';
			tabGrafo.style.backgroundColor = 'white';
			tabGrafo.style.borderRadius = 'revert';
		});
	}
	let tabGrafo = await esperarElemento('tabs-vision[label2="Grafo"] div[aria-posinset="2"]');
	if (tabGrafo) {
		tabGrafo.addEventListener('click', function() {
			this.style.backgroundColor = 'rgba(0, 92, 187, 0.38)';
			this.style.borderRadius = '15px 15px 0 0';
			tabTabelas.style.backgroundColor = 'white';
			tabTabelas.style.borderRadius = 'revert';
		});
	}

	let addBotoesImprimirProcessos = async () => {
		
		if (document.location.href.includes(".pdpj.jus.br/investigacao-de-bens/") && document.querySelector('app-consultation-assets')) {
			
			let listaPartes = await esperarColecao('app-consultation-assets section[class*="parts-container"] mat-card');

			for (const [pos, ancora] of listaPartes.entries()) {
				addBotaoSniperPesquisaProcessos(pos, ancora);
			}
		}
	};
	
}

async function addBotaoSniperPesquisaProcessos(pos, ancora) {

	//container
	let container = document.createElement("mat-card-content");
	container.style = 'display: grid;grid-template-columns: 1fr 1fr;margin: 0 10px 10px 10px;';

	if (!document.getElementById("maispje_sniper_buscarProcessos_" + pos + '_a')) {
		let bt1 = document.createElement("a");
		let ic1 = document.createElement("span");
		bt1.id = "maispje_sniper_buscarProcessos_" + pos + '_a';
		bt1.title = "maisPje";
		ic1.innerText = "🖨️ Dados";
		bt1.style = "cursor: pointer; position: relative; z-index: 100; color: rgb(0, 92, 187); border-radius: 25px; font-weight: 500; width: auto; text-align: center; text-decoration: none;display: inline-block;height: 35px;align-content: center;";
		bt1.onmouseover = function () {
			this.style.backgroundColor = '#ffa50030';
			this.style.color = 'orangered';
		};
		bt1.onmouseleave = function () {
			this.style.backgroundColor = 'revert';
			this.style.color = 'rgb(0, 92, 187)';
		};
		bt1.href = ancora.querySelector('a').href + '?maisPje=dados';
		bt1.appendChild(ic1);

		container.appendChild(bt1)
		// ancora.insertBefore(bt1, ancora.firstChild);				
	}

	if (!document.getElementById("maispje_sniper_buscarProcessos_" + pos + '_b')) {
		let bt2 = document.createElement("a");
		let ic2 = document.createElement("span");
		bt2.id = "maispje_sniper_buscarProcessos_" + pos + '_b';
		bt2.title = "maisPje";
		ic2.innerText = "🖨️ Processos";
		bt2.style = "cursor: pointer; position: relative; z-index: 100; color: rgb(0, 92, 187); border-radius: 25px; font-weight: 500; width: auto; text-align: center; text-decoration: none;display: inline-block;height: 35px;align-content: center;";
		bt2.onmouseover = function () {
			this.style.backgroundColor = '#ffa50030';
			this.style.color = 'orangered';
		};
		bt2.onmouseleave = function () {
			this.style.backgroundColor = 'revert';
			this.style.color = 'rgb(0, 92, 187)';
		};
		bt2.href = ancora.querySelector('a').href + '?maisPje=processos';
		bt2.appendChild(ic2);

		container.appendChild(bt2)
		// ancora.insertBefore(bt2, ancora.firstChild);
	}

	ancora.appendChild(container);
}

async function monitor_janela_cnib() {
	console.log("Extensão maisPJE (" + agora() + "): monitor_janela_cnib");
	let targetDocumento = document.body;
	let observerDocumento = new MutationObserver(async function(mutationsDocumento) {
		mutationsDocumento.forEach(async function(mutation) {
		if (!mutation.addedNodes[0]) { return }

		if (mutation.addedNodes[0]) {
			if (!mutation.addedNodes[0].tagName) { return }
			console.log(mutation.addedNodes[0].tagName + " : " + mutation.addedNodes[0].className + " : " + mutation.addedNodes[0].innerText); //excluir após os testes
			if (mutation.addedNodes[0].tagName == 'TABLE' && mutation.addedNodes[0].id == 'tbParties') {
				let pai = mutation.addedNodes[0].parentElement;
				pai.style.setProperty('max-height','100%');
				pai.style.setProperty('height','auto%');
			}

			if (mutation.addedNodes[0].tagName == 'LABEL' && mutation.addedNodes[0].innerText.includes('FOI AUTORIZADO O CANCELAMENTO DA INDISPONIBILIDADE')) {
				// LABEL : fw-bold text-danger : FOI AUTORIZADO O CANCELAMENTO DA INDISPONIBILIDADE ABAIXO
				let bt = await esperarElemento('a[href*="/relatorio/cancelamento/detalhe"]','Imprimir');
				if (bt) { 
					console.log('maisPJe: CNIB: clicando em Imprimir ordem de Cancelamento'); 
					bt.scrollIntoView({behavior: 'smooth',block: 'start'});
					await timer(bt, preferencias.modulo9.cnib[7], 'orangered', 'pulseGeral')
					if (preferencias.modulo9.cnib[3]) {
						let opcoes = await criarCaixaCheckBox(['Sim','Não'], [true,false], 'Você deseja executar a AA ' + preferencias.modulo9.cnib[6] + ' no processo agora?',false,'Continuar');
						if (opcoes[0]) {
							browser.runtime.sendMessage({tipo: 'storage_vinculo', valor: preferencias.modulo9.cnib[6]});
							await sleep(2000); //esperar abrir a janela
						} else {
							document.location.href = 'https://indisponibilidade.onr.org.br/dashboard?maispjecancelarminuta'
						}
					}
				}
			}

			if (mutation.addedNodes[0].className == 'ufSearchSuggestionContainer') {
				addBotaoSelecionarTodos();
			}

			if (mutation.addedNodes[0].tagName == 'DIV' && mutation.addedNodes[0].className.includes('wizard-circle') && mutation.addedNodes[0].className.includes('selected')) {
				if (preferencias.modulo9.cnib[1]) {
					let passo = await esperarElemento('div[class="wizard-circle selected"] span');
					// console.log(passo.innerText)
					if (passo.innerText == '1') {
						await clicarBotao('#maisPje_menuKaizen_itemmenu_preencher_campos a'); //preencher campos automaticamente
					}
				}
			}

			if (mutation.addedNodes[0].tagName == 'BUTTON' && mutation.addedNodes[0].innerText.includes('Continuar para indisponibilidade genérica')) {
				if (preferencias.modulo9.cnib[2]) {
					await clicarBotao(mutation.addedNodes[0]);
				}
			}

			if (mutation.addedNodes[0].tagName == 'INPUT' && mutation.addedNodes[0].value == "Enviar Indisponibilidade") {
				if (preferencias.modulo9.cnib[3]) {
					await clicarBotao(mutation.addedNodes[0]);				
					await clicarBotao('#btnSimModal')
				}
			}

			if (mutation.addedNodes[0].tagName == 'BUTTON' && mutation.addedNodes[0].innerText.includes('Ver Detalhes do Protocolo IA')) {
				if (preferencias.modulo9.cnib[3]) {
					await clicarBotao(mutation.addedNodes[0]);
				}
			}

			if (mutation.addedNodes[0].tagName == 'LABEL' && mutation.addedNodes[0].className.includes('lblValorDescricao')) { //copia o numero do protocolo para a memoria
				if (preferencias.modulo9.cnib[4]) {
					let padraoProtocoloCNIB = /\d{6}\.\d{4}\.\d{8}\-IA-\d{3}/gm
					let texto = mutation.addedNodes[0].innerText;
					if (padraoProtocoloCNIB.test(texto)) {
						navigator.clipboard.writeText(texto.match(padraoProtocoloCNIB).join());
					}
				}
			}

			if (mutation.addedNodes[0].tagName == 'BUTTON' && mutation.addedNodes[0].innerText.includes('Imprimir')) {
				await clicarBotao(mutation.addedNodes[0]);
				await sleep(preferencias.modulo9.cnib[7]*1000)
				if (preferencias.modulo9.cnib[3]) { //imprime e executa AACnib de inclusão
					browser.runtime.sendMessage({tipo: 'storage_vinculo', valor: preferencias.modulo9.cnib[5]});
				}
			}

			//erro: ordem pertence a outra instituição
			if (mutation.addedNodes[0].tagName == 'SPAN' && mutation.addedNodes[0].innerText.includes('A ordem de indisponibilidade pesquisada não pertence a esta instituição')) {
				
				let aviso = mutation.addedNodes[0].parentElement.parentElement.parentElement.parentElement.parentElement.parentElement.parentElement.parentElement.parentElement.parentElement;
				aviso.style.transform = 'translateX(-30vw)';
				
				await sleep(preferencias.modulo9.cnib[7]*1000)
				await clicarBotao('#linkChangeProfile');

			}
			

			
		}
		});
	});
	let configDocumento = { childList: true, subtree:true }
	observerDocumento.observe(targetDocumento, configDocumento); //inicia o MutationObserver

	function addBotaoSelecionarTodos() {
		if (document.querySelector('#maisPJe_SelecionarTodos')) { return }
		let ancora = document.querySelector('.ufSearchSuggestionContainer');
		let novoBt = document.createElement('div');
		novoBt.id = 'maisPJe_SelecionarTodos';
		novoBt.className = 'ufSearchSuggestion';
		novoBt.onclick = async function() {
			if (this.className.includes('ufSearchSuggestion-selected')) {
				this.classList.remove('ufSearchSuggestion-selected'); 
			} else {
				this.classList.add('ufSearchSuggestion-selected'); 	
			}
			
			let lista = document.querySelectorAll('.ufSearchSuggestion');
			for (const [pos, item] of lista.entries()) {
				console.log(pos)
				if (pos > 0) { // o 0 é o TODOS, ignora ele
					item.click();
					if (pos == 1) { 
						let barraDeProgresso = await esperarElemento('div[class*="progress-box"]')
						await esperarDesaparecer(barraDeProgresso);
					}
				}
			}
			
		}
		let novoLabel = document.createElement('label');
		novoLabel.innerText = "TODOS";
		novoBt.appendChild(novoLabel);
		ancora.insertBefore(novoBt,ancora.firstChild);
	}
}

async function monitor_janela_onr(acao) {
	
	let janela = await esperarElemento('frame[name="contents"]');
	let janelaBody;

	//IFRAMEPRINCIPAL
	if (janela) {
		janelaBody = janela.contentDocument || janela.contentWindow.document;
		if (!janelaBody) { return }
	}

	let cabecalho = janelaBody.getElementById('menupenhora');
	//CABECALHO
	if (cabecalho) {
		let el_docto_conteudo_cabecalho = cabecalho.contentDocument || cabecalho.contentWindow.document;
		if (!el_docto_conteudo_cabecalho) { return }
		el_docto_conteudo_cabecalho.addEventListener('click', function(event) {			
			console.log(event.target.tagName)
			monitorarCorpo(janelaBody);
		});
	}			


	async function monitorarCorpo(janelaBody) {

		let check = setInterval(function() {
			console.log('*')
			//CORPO
			let corpo = janelaBody.getElementById('mainpenhora');
			if (corpo) {
				let ifr = corpo.contentDocument || corpo.contentWindow.document;			
				if (!ifr) { return }
				
					if (ifr.querySelector('#msgNumeroPenhora')) {
						if (!ifr.querySelector('#msgNumeroPenhora').hasAttribute('maisPJe')) {
							let var1 = browser.storage.local.get(['processo_memoria'], async function(result){
								preferencias.processo_memoria = result.processo_memoria;						
								
								Object.getOwnPropertyDescriptor(window.HTMLInputElement.prototype, 'value').set.call(ifr.querySelector('#msgNumeroPenhora'), preferencias.processo_memoria.numero);
								ifr.querySelector('#msgNumeroPenhora').setAttribute('maisPJe','true');
								
								if (ifr.querySelector('#dplNomeAcaoPenhora')) {
									ifr.querySelector('#dplNomeAcaoPenhora option[value="2"]').selected = true;
								}

							});						
						}
					}
					
					
			}
		}, 1000);
	}

	

}

