//FUNÇÃO DE EXIBIÇÃO DA LOCALIZAÇÃO DO PROCESSO NA PAUTA DE PERÍCIAS
async function painelPericiaTarefaProcesso() {
	fundo(true)
	let listaNum = document.querySelector('table[name="Tabela de Perícias"]').innerText.match(padraoProcesso).join().split(",");
	let listaTarefa = [];
	
	for (const [pos, processo] of listaNum.entries()) {
		let data1 = await obterIdProcessoViaApiPublica(processo);
		let data3 = await obterNomeTarefaDoProcessoViaApi(data1[0].id);
		listaTarefa.push(data3);
	}
	
	montarInformações();
	fundo(false);

	async function montarInformações() {
		console.log("montar informações");
		let el = document.querySelectorAll('a[aria-label*="Abrir tarefa do processo"]');
		if (!el) {
			return
		}
		for (const [pos, linha] of el.entries()) {
			let numeroProcesso = linha.innerText.match(padraoProcesso).join();
			let posicao = listaNum.indexOf(numeroProcesso);
			let div = document.createElement("div");
			div.textContent = "Tarefa: ";
			div.style = "font-weight: normal;font-size: 1em;background-color:#00800061;";
			let i = document.createElement("i");
			i.style = "font-style: normal;";
			let tarefa = listaTarefa[posicao];
			i.textContent = tarefa;
			if (tarefa.toLowerCase().includes('arquivo')) {
				div.style.backgroundColor = "#ff00004f";
			} else if (tarefa.toLowerCase().includes('sobrestamento')) {
				div.style.backgroundColor = "#ffa50063";
			}
			div.appendChild(i);
			linha.parentElement.appendChild(div);
		}
	}
}

//FUNÇÃO QUE ATRIBUI AUTOMATICAMENTE O MAGISTRADO RESPONSAVEL PELA MINUTA DESPACHO/DECISÃO/SENTENÇA
//DE ACORDO COM O NÚMERO FINAL DO PROCESSO - MÓDULO 8
async function filtroMagistrado(processoNumero) {
	return new Promise(async resolve => {
		if (!preferencias.modulo8) {return resolve("")}
		if (preferencias.modulo8.length < 1) {return resolve("")}
		
		//se informar o numero do processo a função retorna o nome do magistrado
		if (processoNumero) {
			let numero = processoNumero.substring(0, 7);
			let ano = processoNumero.substring(11, 15);
			let ultimo;
			let pos1 = (ano > 2009) ? 6 : 4;
			let pos2 = (ano > 2009) ? 7 : 5;
			
			ultimo = numero.substring(pos1, pos2);
			
			//ignora zero
			console.log('ultimo: ' + ultimo)
			if (preferencias.modulo8_ignorarZero) {

				while(true) {
					
					if (ultimo > 0) { break }

					pos1--;
					pos2--;

					ultimo = numero.substring(pos1, pos2);
				}
				
				console.log('ultimo: ' + ultimo)
			}			
			
			if (!ultimo) {
				return resolve("")
			}

			//encontra a regra
			let magistrado = "";
			let orgaoJulgadorCargo;

			//Nos convênios a regra OJCargo deve ser ignorada
			if (document.getElementById('maisPje_menuConvenios')) {
				orgaoJulgadorCargo = await obterOrgaoJulgadorCargo(processoNumero);
			} else {
				orgaoJulgadorCargo = 'TODOS';
			}

			//usa o orgão julgador cargo da memoria pois a api sendo consultada da pagina do sisbajud da erro 400
			orgaoJulgadorCargo = await obterOrgaoJulgadorCargo(processoNumero);
			if (!orgaoJulgadorCargo) {
				if (preferencias.processo_memoria.numero && processoNumero == preferencias.processo_memoria.numero) {
					orgaoJulgadorCargo = preferencias.processo_memoria.orgaoJulgadorCargo				
				} else {
					await criarCaixaDeAlerta('ATENÇÃO','Não foi possível obter o órgão Julgador CARGO do processo ' + processoNumero + '.\n Confira o magistrado selecionado automaticamente pela extensão maisPJe.',3);
					orgaoJulgadorCargo = 'TODOS';
				}
			}			

			orgaoJulgadorCargo = orgaoJulgadorCargo.toUpperCase(); //traz para caixa alta

			for (const [pos, item] of preferencias.modulo8.entries()) {
				let regra = item.split('|');
				let nomeJuiz = regra[10];
				let regraPorFinalDoProcesso = (/true/gi).test(regra[ultimo]);
				let regraOJ = (regra[11] == preferencias.oj_usuario || regra[11] == 'TODOS' || !regra[11]);
				if (!regra[12]) { regra[12] = 'TODOS' }
				let regraOJCargo = (orgaoJulgadorCargo.includes(regra[12]) || regra[12] == 'TODOS' || !regra[12]);
				
				//Nos convênios a regra OJCargo deve ser ignorada
				regraOJCargo = (orgaoJulgadorCargo == 'TODOS') ? true : regraOJCargo;

				console.log("REGRA " + pos);
				console.log("  |___Juiz: " + nomeJuiz);
				console.log("  |___Digito " + ultimo + ': ' + regraPorFinalDoProcesso);
				console.log("  |___OJ: " + regra[11] + " == " + preferencias.oj_usuario + " : " + regraOJ);
				console.log("  |___OJC: " + regra[12] + " == " + orgaoJulgadorCargo + " : " + regraOJCargo);
				console.log("      __________________________");
				console.log("        " + (regraPorFinalDoProcesso && regraOJ && regraOJCargo))
				if (regraPorFinalDoProcesso && regraOJ && regraOJCargo) {
					magistrado = nomeJuiz;
					break;
				}
				
			}
			console.log("Magistrado encontrado: " + magistrado);
			
			return resolve(magistrado);
		} else { //caso contrário ela escolhe o magistrado no campo 
			await esperarElemento('span[class="texto-numero-processo"]');
			//recupera o numero final do processo
			processoNumero = await obterNumeroDoProcessoNaTela();
			processoNumero = await decomporNumeroProcesso(processoNumero.toString());			
			if (!processoNumero.ultimo) { return resolve(false)	}

			//encontra a regra
			let magistrado = "";
			let orgaoJulgadorCargo = await obterOrgaoJulgadorCargo(processoNumero.completo);
			orgaoJulgadorCargo = orgaoJulgadorCargo.toUpperCase(); //traz para caixa alta

			for (const [pos, item] of preferencias.modulo8.entries()) {
				let regra = item.split('|');
				let nomeJuiz = regra[10];
				let regraPorFinalDoProcesso = (/true/gi).test(regra[processoNumero.ultimo]);
				let regraOJ = (regra[11] == preferencias.oj_usuario || regra[11] == 'TODOS' || !regra[11]);
				let regraOJCargo = (orgaoJulgadorCargo.includes(regra[12]) || regra[12] == 'TODOS' || !regra[12]);

				console.log("REGRA " + pos);
				console.log("  |___Juiz: " + nomeJuiz);
				console.log("  |___Digito " + processoNumero.ultimo + ': ' + regraPorFinalDoProcesso);
				console.log("  |___OJ: " + regra[11] + " == " + preferencias.oj_usuario + " : " + regraOJ);
				console.log("  |___OJC: " + regra[12] + " == " + orgaoJulgadorCargo + " : " + regraOJCargo); 
				// tem que fazer includes (titular e substituto)
				console.log("      __________________________");
				console.log("        " + (regraPorFinalDoProcesso && regraOJ && regraOJCargo))
				if (regraPorFinalDoProcesso && regraOJ && regraOJCargo) {
					magistrado = nomeJuiz;
					break;
				}
				
			}
			console.log("Magistrado encontrado: " + magistrado);
			
			//escolhe o magistrado
			await escolherOpcao('mat-select[placeholder="Magistrado"]', magistrado, 2);
			await sleep(preferencias.maisPje_velocidade_interacao + 500);
			//espera por dois segundos pela regra de impedimento ou suspeição, bem como para recarregar os botões (eles mudam sempre que troca o juiz)
			let impedimento_suspeição = await esperarElemento('i[mattooltip="Existe impedimento ou suspeição para este Magistrado"]', null, 2000);
			if (impedimento_suspeição) {
				fundo(false);
				criarCaixaDeAlerta("ALERTA","Atenção, o(a) Magistrado(a) possui regra de suspeição/impedimento ativa para este processo!");
				return;
			}
			return resolve(true);
		}
	});
}

