async function teste_mutation_observer() {
	console.log('teste_mutation_observer()');
	let primeiraCamada = await ObterCamadaUm();
	// ObterMutationFinal();
	
	async function ObterCamadaUm() {
		return new Promise(async resolve => {
			// let el_docto = await esperarElemento('frame[name="contents"]');
			// let el_docto_conteudo = el_docto?.contentDocument || el_docto?.contentWindow?.document;
			
			// let alvo = document.body;
			// let alvo = await esperarElemento('div[class="loading-container"]'); //div[class="loading-container"]
			let alvo = document.body;
			await ligarMOCamadaUm(alvo);
			return resolve(el_docto_conteudo);
		});
	}
	
	function ligarMOCamadaUm(alvo) {
		return new Promise(async resolve => {
			console.log('ligarMOCamadaUm')			
			let observer_cabecalho = new MutationObserver(function(mutationsDocumento) {
				mutationsDocumento.forEach(function(mutation) {

					// if (mutation.type === "attributes") {
					// 	console.log(`The ${mutation.attributeName} attribute was modified para ${mutation.oldValue}.`);
					// 	console.log(mutation.target.className)
				  	// }

					if (!mutation.removedNodes[0] && !mutation.addedNodes[0]) { return }
					
					if (mutation.removedNodes[0]) {
						if (!mutation.removedNodes[0].tagName) { return }
						console.log("---[DEL] tagName(" + mutation.removedNodes[0].tagName + ") id(" + mutation.removedNodes[0].id + ") className(" + mutation.removedNodes[0].className + ")");
						console.log("---    |___" + mutation.removedNodes[0].innerText);
						console.log("---    |___" + mutation.removedNodes[0].parentElement);
					}
					
					if (mutation.addedNodes[0]) {
						if (!mutation.addedNodes[0].tagName) { return }
						console.log("+++[ADD] tagName(" + mutation.addedNodes[0].tagName + ") id(" + mutation.addedNodes[0].id + ") className(" + mutation.addedNodes[0].className + ")");
						console.log("+++    |___" + mutation.addedNodes[0].innerText);
					}
				});
			});
			let configDocumento = { childList: true, subtree:true, attributes: true }
			observer_cabecalho.observe(alvo, configDocumento);
			
			
		});
	}
}

//FUNÇÃO QUE AGUARDA O ÚLTIMO MUTATION LANÇADO. PODEMOS TER VÁRIAS REMESSAS DE MUTATION. 
//ESSA FUNÇÃO SEMPRE DISPARA APENAS NO ÚLTIMO MUTAIUTON DE CADA REMESSA
// unicaVez == true : assim que a função identifica o ultimo mutation ela desliga.. se for false, ela permanece identificando mudanças na pagina
//segundos == qtdade de tempo que a extensão fica escutando os mutations.. decorrido o tempo ela aciona a função
async function aguardarUltimoMutation(minhaFuncao,unicaVez=false) { 
	return new Promise(async resolve => {
		console.log('maisPJe: aguardarUltimoMutation...')
		let timer;
		let segundos = 0
		let uObserver = new MutationObserver(function(mutations) {			
			let segundos = 2750 + parseInt(preferencias.maisPje_velocidade_interacao); //na velocidade máxima corresponde a 3 segundos
			if (timer) clearTimeout(timer);
			timer = setTimeout(() => {
				mutations.forEach(function(mutation) {
					// console.log('ultimo mutation***********************************************************' + timer);
					if (unicaVez) { uObserver.disconnect() }
					minhaFuncao();
					return resolve(true);					
				});
			}, segundos);
		});
		uObserver.observe(document.body, { childList: true });
	});
}

