async function extrairComandosComuns(texto) { //converte a string em objeto: ex: ["intimar:sim","prazo:30","enviarpec:não"] se transforma em Object { intimar: "sim", prazo: "30", enviarpec: "não" }
	let padrao = /\[.+\]/gm;
	let txt = '';
	if (padrao.test(texto)) {
		txt = texto.match(padrao).join();
		txt = txt.replace('[','');
		txt = txt.replace(']','');
		
		//exclui o ultimo ponto e virgula, caso exista
		let ultimoCaractere = txt.slice(-1);
		if (ultimoCaractere == ';') { txt = txt.slice(0,-1) }
		
		let json = txt.split(';').map(elements => JSON.parse(`{"${elements?.split(':')?.join('":"')}"}`));
		let resposta = Object.create({});
		let map = [].map.call(
			json, 
			function(obj) {
				resposta = { ...resposta, ...obj}				
			}
		);
		return resposta;
	} else {
		return null;
	}
}

function toISOFormat(dateTimeString) {
	const [date, time] = dateTimeString.split(' ');
	const [DD, MM, YYYY] = date.split('/');
	const [HH, mm] = time.split(':');
	return `${YYYY}-${MM}-${DD}T${HH}:${mm}`;
}

//DESCRIÇÃO: Esse trecho de código serve para quando houver seleção de item no MENU, este item seja copiado para o clipboard (memória), assim é possível utilizado em 
//outros navegadores através do "CTRL + V".
async function copiarClipboard(t) {
	//Porém, para copiar para a memória é necessário criar um elemento falso na página uma vez que o comando "document.execCommand("copy")" só aceita textos selecionados.
	// var textarea = document.createElement("textarea");
	// textarea.textContent = texto;
	// document.body.appendChild(textarea);
	// textarea.select();
	// document.execCommand("copy");
	// document.body.removeChild(textarea)

	//***Atualização de comando.. por questão de segurança 
	try {
		await navigator.clipboard.writeText(t);		
	} catch (e) {
		console.error('Não foi possível efetuar o comando copiar (Ctrl + C)..');
	}
}

function numeroProcessoFormatado(texto) {
	texto = extrairNumeros(texto);
	return texto.replace(/(\d{7})(\d{2})(\d{4})(\d{1})(\d{2})(\d{4})/,"$1-$2.$3.$4.$5.$6");
}

function numeroContaSIFFormatado(texto) {
	texto = extrairNumeros(texto);
	return texto.replace(/(\d{4})(\d{3})(\d{8})(\d{1})/,"$1.$2.$3-$4");
}

function numeroDataFormatado(texto,separador='/') {
	texto = extrairNumeros(texto);
	if (texto.length == 8) { //ano 4 digitos 00123456
		return texto.replace(/(\d{2})(\d{2})(\d{4})/,"$1" + separador + "$2" + separador + "$3");
	} else if (texto.length == 6) { //ano 2 digitos
		return texto.replace(/(\d{2})(\d{2})(\d{2})/,"$1" + separador + "$2" + separador + "$3");
	} else {
		return null;
	}
}

function numeroValorFormatado(valor) {
	if (typeof(valor) == 'string') {
		// valor = valor.replace(".", "").replace(",", "."); //troca a virgula por ponto
		let padrao =/(\d{1,}\.\d{2})|(\d{1,})/;	
		if (padrao.test(valor)) {
			valor = valor.match(padrao).join();
			return Intl.NumberFormat('pt-br', {style: 'decimal', currency: 'BRL', minimumFractionDigits: 2}).format(parseFloat(valor));
		} else {
			return null;
		}
	} else { //number
		return Intl.NumberFormat('pt-br', {style: 'decimal', currency: 'BRL', minimumFractionDigits: 2}).format(parseFloat(valor));
	}
	
}

function obterIdProcessoDaUrl(url) {
	return new Promise(resolve => {
		
		url = (!url) ? document.location.href : url;		
		let padrao = /\/{1}\d{5,}\/{1}/;
		let texto = url?.match(padrao)?.join();

		if (url.includes('/processo/') && url.includes('/detalhe')) { //janela Detalhes
			texto = url.match(padrao).join();
		} else if (url.includes('/processo/') && url.includes('/tarefa/') && url.includes('/minutar')) { //janela tarefa Despachos
			texto = url.match(padrao).join();
		} else if (url.includes('/processo/') && url.includes('/tarefa/')  && url.includes('/comunicacoesprocessuais/minutas')) { //janela Tarefa Intimações
			texto = url.match(padrao).join();
		} else if (url.includes('/processo/') && url.includes('/comunicacoesprocessuais/minutas')) { //janela Detalhes Intimações
			texto = url.match(padrao).join();
		} else if (url.includes('/processo/') && url.includes('/documento/anexar')) { //janela Anexar Documentos
			texto = url.match(padrao).join();
		} else if (url.includes('/pje-gigs-api/api/execucao/processo/')) { //janela Principal > GIGS > execucao
			padrao = /\/{1}\d{5,}/;
			texto = url.match(padrao).join();
		}
		let idProcesso = extrairNumeros(texto);
		return resolve(idProcesso);

	});
}

function obterIdDocumentoDaUrl(url) {
	return new Promise(resolve => {
		
		url = (!url) ? document.location.href : url;		
		let padrao = /\/{1}\d{8,}\?{1}/;
		let texto = url?.match(padrao)?.join();

		if (url.includes('/pjekz/processo/') && url.includes('/documento/') && url.includes('/conteudo')) { //janela isolada do documento
			padrao = /\/{1}\d{8,}\/{1}/;
			texto = url.match(padrao).join();
		}
		
		let idDocumento = extrairNumeros(texto);
		return resolve(idDocumento);

	});
}

async function obterUrlDoNetworkRequest(queContem, trocaDePerfil=false) {	
	return new Promise(async resolve => {
		let capture_resource = performance.getEntriesByType("resource");
		let startTimeUltimoNR = capture_resource[capture_resource.length - 1].startTime;
		
		//obtém a lista de NR's do ultimo segundo e confere se ela é um dos request's de filtro
		let requestName = 'Nenhum';
		let houvetroca = false;
		for (let i = 0; i < capture_resource.length; i++) {			
			if (capture_resource[i].startTime > (startTimeUltimoNR-1000))  {
				// console.log('------------------------------------' + capture_resource[i].name);
				if (trocaDePerfil) {
					if (capture_resource[i].name.includes('pje-seguranca/api/token/perfis/trocar')) { //troca de perfil
						houvetroca = true;
					} else if (houvetroca) {
						if (capture_resource[i].name.includes(queContem)) {			
							// console.log('------------------------------------|_____________' + capture_resource[i].name);
							requestName = capture_resource[i].name;
							break;					
						}
					}

				} else {
					if (capture_resource[i].name.includes(queContem)) {			
						requestName = capture_resource[i].name;
						break;					
					}
				}				
			}				
		}
		// console.log('------------------------------------***********************************' + requestName);
		return resolve(requestName);		
	});
}

function obterRitoProcessoDoTexto(texto) {
	return new Promise(resolve => {
		
		let padrao = /[A-Za-z]{5,}/;
		texto = texto?.match(padrao)?.join();
		return resolve(texto);

	});
}

function consultaPJe(el) {
	if (document.getElementById('maisPJe_atalhoConsultaPJe')) { return }
	console.log("      |___criado link para consulta no PJe");
	if (!el || el.length == 0) { return }
	let padraoProcesso = /\d{7}\-\d{2}\.\d{4}\.\d{1}\.\d{2}\.\d{4}/g; 	
	if (!el.length) {
		inserirbotao(el, el.innerText.match(padraoProcesso).join());
	} else {
		let map = [].map.call(
			el, 
			function(elemento) {
				if (padraoProcesso.test(elemento.innerText)) { inserirbotao(elemento, elemento.innerText.match(padraoProcesso).join()) }
			}
		);
	}
	
	function inserirbotao(elemento, processo) {
		//insere o pacote de ícones
		browser.runtime.sendMessage({tipo: 'insertCSS', file: 'maisPje_icones.css'});
		
		//CRIA BOTÃO CONSULTA RAPIDA DE PROCESSOS
		let atalho = document.createElement("a");
		atalho.id = "maisPJe_atalhoConsultaPJe";
		atalho.style = 'display: inline-block; position: absolute; z-index: 100; width: 28px; height: 28px; text-align: center; color: black;';
		atalho.setAttribute('title','Consultar Processo no PJe');
		
		let check;
		let mouseEmCima = false; 
		atalho.onmouseenter = function (event) {				
			event.preventDefault();
			if (mouseEmCima) { return }
			// console.log('entrou')
			this.firstElementChild.style.animation = 'trocarCor 1s';
			mouseEmCima = true;
			let seg = 1;
			check = setInterval(function() {
				seg--;
				if (mouseEmCima && seg < 1) {
					clearInterval(check);
					console.log('acionou')
					mouseEmCima = false;
					browser.storage.local.get('oj_usuarioId', function(result){
						console.log(preferencias.oj_usuarioId)
						preferencias.oj_usuarioId = result.oj_usuarioId
						console.log(preferencias.oj_usuarioId)
						consultaRapidaPJE(processo) 
					});
				}			
				
			}, 1000);
		};
		atalho.onmouseleave = function (event) {				
			event.preventDefault();
			// console.log('saiu')
			this.firstElementChild.style.animation = 'unset';
			mouseEmCima = false;
			clearInterval(check);
		};
		
		atalho.onclick = function () { 
			clearInterval(check);
			browser.storage.local.get('oj_usuarioId', function(result){
				console.log(preferencias.oj_usuarioId)
				preferencias.oj_usuarioId = result.oj_usuarioId
				console.log(preferencias.oj_usuarioId)
				consultaRapidaPJE(processo) 
			});
			
		};
		let i = document.createElement("i");
		i.className = "search";
		i.style = "display: inline-block; font-style: normal; font-variant: normal; text-rendering: auto; line-height: 1; cursor: pointer; width: 2vh; height: 2vh; background-color: black;";
		atalho.appendChild(i);						
		elemento.appendChild(atalho);
	}
}

async function existeDoctoNaoAssinado(param) {
	return new Promise(
		async resolver => {
			let idProcesso;
			if (param.length > 15) { //eh o numero
				let api = await obterIdProcessoViaApi(param);
				if (!api) { return resolver(null) }
				if (!api[0].idProcesso) { return resolver(null) }
				idProcesso = api[0].idProcesso;
			} else { //é o id
				idProcesso = param;
			}
			
			
			let alertarSobreDocumentosNaoAssinados = false;
			
			//confere processos pendente no anexa documentos
			await obterInfoDocToNaoAssinado(idProcesso).then(resultado => {
				if (resultado) {
					alertarSobreDocumentosNaoAssinados = true;
				}
			});

			await obterNomeTarefaDoProcessoViaApi(idProcesso).then(resultado => {
				//confere processos pendente no preparar comunicação/expedientes, despachos, decisão e sentença
				if (resultado.includes('Assinar ')) {
					alertarSobreDocumentosNaoAssinados = true;
				}
			});

			return resolver(alertarSobreDocumentosNaoAssinados);
		}
	);
}


